**`resolveAncestry()` helper:**

```typescript
type Ancestry = {
  project?: { id: string; name: string };
  feature?: { id: string; name: string };
};

async function resolveAncestry(
  client: BrainHttpClient,
  detail: EntityDetailResult,
  entityType: SupportedType,
): Promise<Ancestry> {
  if (entityType === "project") {
    return { project: { id: detail.entity.id, name: detail.entity.name } };
  }

  if (entityType === "feature") {
    const parentProject = detail.relationships.find(
      (r) => r.kind === "project" && r.relationKind === "has_feature" && r.direction === "incoming",
    );
    return {
      project: parentProject ? { id: parentProject.id, name: parentProject.name } : undefined,
      feature: { id: detail.entity.id, name: detail.entity.name },
    };
  }

  // entityType === "task"
  // Try direct project relationship first
  const directProject = detail.relationships.find(
    (r) => r.kind === "project" && r.direction === "outgoing" && r.relationKind === "belongs_to",
  );

  const parentFeature = detail.relationships.find(
    (r) => r.kind === "feature" && r.relationKind === "has_task" && r.direction === "incoming",
  );

  let project: Ancestry["project"];

  if (directProject) {
    project = { id: directProject.id, name: directProject.name };
  } else if (parentFeature) {
    // Resolve feature's parent project via a second HTTP call
    try {
      const featureDetail = (await client.getEntityDetail(
        `feature:${parentFeature.id}`,
      )) as EntityDetailResult;
      const featureParentProject = featureDetail.relationships.find(
        (r) => r.kind === "project" && r.relationKind === "has_feature" && r.direction === "incoming",
      );
      if (featureParentProject) {
        project = { id: featureParentProject.id, name: featureParentProject.name };
      }
    } catch {
      // Could not resolve feature's project -- proceed without it
    }
  }

  return {
    project,
    feature: parentFeature ? { id: parentFeature.id, name: parentFeature.name } : undefined,
  };
}
```

