```typescript
function featureTemplate(entity: EntityDetailResult["entity"], ancestry: Ancestry): string {
  const lines: string[] = [];
  const projectSuffix = ancestry.project ? ` (project: "${ancestry.project.name}")` : "";
  lines.push(`# Brain: Feature -- "${entity.name}"${projectSuffix}`);
  lines.push("");
  lines.push(`This directory is mapped to brain graph entity \`feature:${entity.id}\`.`);

  if (ancestry.project) {
    lines.push(`Parent project: \`project:${ancestry.project.id}\` ("${ancestry.project.name}").`);
    lines.push("");
    lines.push("When using Brain MCP tools from files in this directory:");
    lines.push(`- Pass \`project_id: "${ancestry.project.id}"\` to project-scoped tools.`);
    lines.push(`- Pass \`context: { project: "${ancestry.project.id}", feature: "${entity.id}" }\` to \`create_provisional_decision\`, \`ask_question\`, \`resolve_decision\`.`);
  } else {
    lines.push("");
    lines.push("When using Brain MCP tools from files in this directory:");
    lines.push(`- Pass \`context: { feature: "${entity.id}" }\` to \`create_provisional_decision\`, \`ask_question\`, \`resolve_decision\`.`);
    lines.push(`- Resolve the parent project from workspace context or call \`get_entity_detail\` with \`entity_id: "feature:${entity.id}"\`.`);
  }

  lines.push(`- This is your default feature scope.`);
  return lines.join("\n");
}
