 1→#!/usr/bin/env bun
 2→
 3→import { runInit } from "./commands/init";
 4→import { runLoadContext, runCheckUpdates, runEndSession } from "./commands/system";
 5→import { runCheckCommit, runLogCommit } from "./commands/git-hooks";
 6→
 7→const args = process.argv.slice(2);
 8→const command = args[0];
 9→const subcommand = args[1];
10→
11→async function main(): Promise<void> {
12→  switch (command) {
13→    case "init":
14→      await runInit();
15→      break;
16→
17→    case "system":
18→      switch (subcommand) {
19→        case "load-context":
20→          await runLoadContext();
21→          break;
22→        case "check-updates":
23→          await runCheckUpdates();
24→          break;
25→        case "end-session":
26→          await runEndSession();
27→          break;
28→        default:
29→          console.error(`Unknown system subcommand: ${subcommand}`);
30→          console.error("Available: load-context, check-updates, end-session");
31→          process.exit(1);
32→      }
33→      break;
34→
35→    case "check-commit":
36→      await runCheckCommit();
37→      break;
38→
39→    case "log-commit":
40→      await runLogCommit();
41→      break;
42→
43→    case "mcp":
44→      // MCP stdio server — import dynamically to avoid loading deps unless needed
45→      const { runMcpServer } = await import("./mcp-server");
46→      await runMcpServer();
47→      break;
48→
49→    case "help":
50→    case "--help":
51→    case "-h":
52→      printHelp();
53→      break;
54→
55→    default:
56→      if (command) {
57→        console.error(`Unknown command: ${command}`);
58→      }
59→      printHelp();
60→      process.exit(command ? 1 : 0);
61→  }
62→}
63→
64→function printHelp(): void {
65→  console.log(`
66→brain — Connect coding agents to the Brain knowledge graph
67→
68→Usage:
69→  brain init                     Set up Brain integration (auth, MCP, hooks, commands, git hooks)
70→  brain system load-context      Load workspace info (SessionStart hook)
71→  brain system check-updates     Check for graph updates (UserPromptSubmit hook)
72→  brain system end-session       End agent session (SessionEnd hook)
73→  brain check-commit             Pre-commit hook: check for task completion
74→  brain log-commit               Deprecated no-op (GitHub webhook ingests commits)
75→  brain mcp                      Start MCP stdio server
76→
77→Environment:
78→  BRAIN_SERVER_URL      Brain server URL (default: http://localhost:3000)
79→  BRAIN_WORKSPACE_ID    Workspace ID (required for init)
80→
81→Config:
82→  ~/.brain/config.json  Per-repo workspace credentials
83→`);
84→}
85→
86→main().catch((error) => {
87→  console.error(error instanceof Error ? error.message : error);
88→  process.exit(1);
89→});
90→

  1→import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
  2→import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
  3→import { z } from "zod";
  4→import { requireConfig } from "./config";
  5→import { BrainHttpClient } from "./http-client";
  6→
  7→export async function runMcpServer(): Promise<void> {
  8→  const config = await requireConfig();
  9→  const client = new BrainHttpClient(config);
 10→
 11→  const server = new McpServer({
 12→    name: "brain",
 13→    version: "0.1.0",
 14→  });
 15→
 16→  // =========================================================================
 17→  // Tier 1 — Read Tools
 18→  // =========================================================================
 19→
 20→  server.tool(
 21→    "get_workspace_context",
 22→    "Lightweight workspace overview: projects with entity counts, hot items (contested decisions, open observations), and active sessions. Already loaded at session start — use to refresh.",
 23→    {},
 24→    async () => {
 25→      const result = await client.getWorkspaceContext();
 26→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
 27→    },
 28→  );
 29→
 30→  server.tool(
 31→    "get_project_context",
 32→    "Full project context: decisions, tasks, questions, observations, suggestions, recent changes. Use when you know which project you're working on.",
 33→    {
 34→      project_id: z.string().describe("Project ID"),
 35→      task_id: z.string().optional().describe("Task ID for additional task-scoped context within the project"),
 36→      since: z.string().optional().describe("ISO timestamp to include recent changes since"),
 37→    },
 38→    async (input) => {
 39→      const result = await client.getProjectContext(input);
 40→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
 41→    },
 42→  );
 43→
 44→  server.tool(
 45→    "get_task_context",
 46→    "Task-focused context: task subgraph (subtasks, dependencies, parent feature, siblings, related sessions) plus project hot items. Project is resolved automatically from the task's graph relationships.",
 47→    {
 48→      task_id: z.string().describe("Task ID"),
 49→    },
 50→    async (input) => {
 51→      const result = await client.getTaskContext(input);
 52→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
 53→    },
 54→  );
 55→
 56→  server.tool(
 57→    "get_active_decisions",
 58→    "Get active decisions grouped by status (confirmed, provisional, contested). Optionally scope to a project and/or area.",
 59→    {
 60→      project_id: z.string().optional().describe("Project ID to scope decisions (omit for workspace-wide)"),
 61→      area: z.string().optional().describe("Category filter: engineering, research, marketing, operations, design, sales"),
 62→    },
 63→    async (input) => {
 64→      const result = await client.getDecisions(input);
 65→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
 66→    },
 67→  );
 68→
 69→  server.tool(
 70→    "get_task_dependencies",
 71→    "Get full dependency tree for a task: what it depends on, what depends on it, and its subtasks.",
 72→    {
 73→      task_id: z.string().describe("Task ID"),
 74→    },
 75→    async (input) => {
 76→      const result = await client.getTaskDependencies(input);
 77→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
 78→    },
 79→  );
 80→
 81→  server.tool(
 82→    "get_architecture_constraints",
 83→    "Get constraints: confirmed decisions (hard constraints) and open observations (warnings/conflicts). Optionally scope to a project.",
 84→    {
 85→      project_id: z.string().optional().describe("Project ID to scope constraints (omit for workspace-wide)"),
 86→      area: z.string().optional().describe("Category filter"),
 87→    },
 88→    async (input) => {
 89→      const result = await client.getConstraints(input);
 90→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
 91→    },
 92→  );
 93→
 94→  server.tool(
 95→    "get_recent_changes",
 96→    "Get entities that changed since a timestamp. Use to see what happened while you were away.",
 97→    {
 98→      project_id: z.string().optional().describe("Project ID to scope changes"),
 99→      since: z.string().describe("ISO timestamp to get changes since"),
100→    },
101→    async (input) => {
102→      const result = await client.getChanges(input);
103→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
104→    },
105→  );
106→
107→  server.tool(
108→    "get_entity_detail",
109→    "Get full detail for any entity including relationships and provenance. Entity ID format: table:id (e.g. decision:abc123).",
110→    {
111→      entity_id: z.string().describe("Entity ID in table:id format"),
112→    },
113→    async (input) => {
114→      const result = await client.getEntityDetail(input.entity_id);
115→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
116→    },
117→  );
118→
119→  server.tool(
120→    "list_pending_suggestions",
121→    "List pending and deferred suggestions from the brain. Use to see what proactive proposals agents have made for your review.",
122→    {
123→      status: z.string().optional().describe("Filter by status: pending (default), accepted, dismissed, deferred, converted"),
124→      category: z.string().optional().describe("Filter by category: optimization, risk, opportunity, conflict, missing, pivot"),
125→      limit: z.number().optional().describe("Max results to return (default 20)"),
126→    },
127→    async (input) => {
128→      const result = await client.listSuggestions(input);
129→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
130→    },
131→  );
132→
133→  // =========================================================================
