174→/** List architecture constraints, optionally scoped to a project */
175→export async function listProjectConstraints(input: {
176→  surreal: Surreal;
177→  workspaceRecord: RecordId<"workspace", string>;
178→  projectRecord?: RecordId<"project", string>;
179→  area?: string;
180→}): Promise<Array<{ text: string; source: string; severity: "hard" | "soft" }>> {
181→  // Constraints come from two sources:
182→  // 1. Decisions marked as confirmed/contested (hard constraints)
183→  // 2. Observations with severity "conflict" or "warning"
184→
185→  const areaFilter = input.area ? `AND category = $area` : "";
186→  const projectFilter = input.projectRecord
187→    ? `AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)`
188→    : "";
189→
190→  const query = `
191→    SELECT summary AS text, "decision" AS source_type, status, id
192→    FROM decision
193→    WHERE workspace = $workspace
194→      ${projectFilter}
195→      AND status IN ["confirmed", "contested"]
196→      ${areaFilter}
197→    ORDER BY created_at DESC LIMIT 30;
198→
199→    SELECT text, "observation" AS source_type, severity, id
200→    FROM observation
201→    WHERE workspace = $workspace
202→      AND status IN ["open", "acknowledged"]
203→      AND severity IN ["conflict", "warning"]
204→    ORDER BY created_at DESC LIMIT 20;
205→  `;
206→
207→  const results = await input.surreal
208→    .query<[Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>(
209→      query,
210→      {
211→        workspace: input.workspaceRecord,
212→        ...(input.projectRecord ? { project: input.projectRecord } : {}),
213→        ...(input.area ? { area: input.area } : {}),
214→      },
215→    )
216→    .collect<[Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>();
217→
218→  const [decisionRows, observationRows] = results;
219→
220→  const constraints: Array<{ text: string; source: string; severity: "hard" | "soft" }> = [];
221→
222→  for (const d of decisionRows) {
223→    constraints.push({
224→      text: d.text,
225→      source: `decision:${(d.id as RecordId<string, string>).id as string}`,
226→      severity: d.status === "contested" ? "hard" : "hard",
227→    });
228→  }
229→
230→  for (const o of observationRows) {
231→    constraints.push({
232→      text: o.text,
233→      source: `observation:${(o.id as RecordId<string, string>).id as string}`,
234→      severity: o.severity === "conflict" ? "hard" : "soft",
235→    });
236→  }
237→
238→  return constraints;
239→}
