442→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
443→  LET $query = string::lowercase(string::trim($q));
444→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
445→
446→  LET $task_rows = SELECT
447→    id,
448→    "task" AS kind,
449→    title AS text,
450→    extraction_confidence AS confidence,
451→    source_message AS sourceMessage,
452→    priority,
453→    created_at
454→  FROM task
455→  WHERE workspace = $workspace
456→    AND extraction_confidence != NONE
457→    AND string::contains(string::lowercase(title), $query)
458→  ORDER BY created_at DESC
459→  LIMIT $safe_limit;
460→
461→  LET $decision_rows = SELECT
462→    id,
463→    "decision" AS kind,
464→    summary AS text,
465→    extraction_confidence AS confidence,
466→    source_message AS sourceMessage,
467→    priority,
468→    created_at
469→  FROM decision
470→  WHERE workspace = $workspace
471→    AND extraction_confidence != NONE
472→    AND string::contains(string::lowercase(summary), $query)
473→  ORDER BY created_at DESC
474→  LIMIT $safe_limit;
475→
476→  LET $question_rows = SELECT
477→    id,
478→    "question" AS kind,
479→    text AS text,
480→    extraction_confidence AS confidence,
481→    source_message AS sourceMessage,
482→    priority,
483→    created_at
484→  FROM question
485→  WHERE workspace = $workspace
486→    AND extraction_confidence != NONE
487→    AND string::contains(string::lowercase(text), $query)
488→  ORDER BY created_at DESC
489→  LIMIT $safe_limit;
490→
491→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
492→};
