  9→export async function runInit(): Promise<void> {
 10→  const serverUrl = process.env.BRAIN_SERVER_URL ?? DEFAULT_SERVER_URL;
 11→  const workspaceId = process.env.BRAIN_WORKSPACE_ID;
 12→
 13→  const gitRoot = findGitRoot(process.cwd());
 14→  if (!gitRoot) {
 15→    console.error("Not inside a git repository. Run brain init from a project directory.");
 16→    process.exit(1);
 17→  }
 18→
 19→  if (!workspaceId) {
 20→    console.error("Set BRAIN_WORKSPACE_ID env var to your workspace ID.");
 21→    console.error("Find it in the Brain web UI or the database.");
 22→    process.exit(1);
 23→  }
 24→
 25→  console.log("Brain Init\n──────────\n");
 26→
 27→  // Step 1: Auth
 28→  await setupAuth(serverUrl, workspaceId, gitRoot);
 29→
 30→  // Step 2: .mcp.json
 31→  await setupMcpJson(gitRoot);
 32→
 33→  // Step 3: .claude/settings.json hooks
 34→  await setupClaudeHooks(gitRoot);
 35→
 36→  // Step 4: CLAUDE.md
 37→  await setupClaudeMd(gitRoot);
 38→
 39→  // Step 5: Commands
 40→  await setupCommands(gitRoot);
 41→
 42→  // Step 6: Git hooks
 43→  installGitHooks(gitRoot);
 44→
 45→  console.log(`\nDone. Restart Claude Code to activate.`);
 46→}
