 52→async function setupAuth(serverUrl: string, workspaceId: string, gitRoot: string): Promise<void> {
 53→  const global = await loadGlobalConfig();
 54→  const existing = global?.repos[gitRoot];
 55→  if (existing && existing.workspace === workspaceId) {
 56→    console.log(`✓ Auth: already configured for ${gitRoot}`);
 57→    return;
 58→  }
 59→
 60→  const initResult = await BrainHttpClient.initApiKey(serverUrl, workspaceId);
 61→  await saveRepoConfig(serverUrl, gitRoot, {
 62→    workspace: workspaceId,
 63→    api_key: initResult.api_key,
 64→  });
 65→  console.log(`✓ Auth: API key saved for ${gitRoot} → workspace "${initResult.workspace.name}"`);
 66→}
