 91→// ---------------------------------------------------------------------------
 92→// Step 3: .claude/settings.json hooks
 93→// ---------------------------------------------------------------------------
 94→
 95→type HookEntry = { type: string; command?: string; prompt?: string };
 96→type SettingsHookGroup = { matcher?: string; hooks: HookEntry[] };
 97→
 98→async function setupClaudeHooks(gitRoot: string): Promise<void> {
 99→  const claudeDir = join(gitRoot, ".claude");
100→  if (!existsSync(claudeDir)) mkdirSync(claudeDir, { recursive: true });
101→
102→  const settingsPath = join(claudeDir, "settings.json");
103→  const file = Bun.file(settingsPath);
104→  let settings: Record<string, unknown> = {};
105→
106→  if (await file.exists()) {
107→    try {
108→      settings = await file.json();
109→    } catch {
110→      // Corrupted — start fresh
111→    }
112→  }
113→
114→  const hooks = (settings.hooks ?? {}) as Record<string, SettingsHookGroup[]>;
115→  let added = 0;
116→
117→  for (const [event, hookDefs] of Object.entries(BRAIN_HOOKS)) {
118→    hooks[event] ??= [];
119→
120→    const hasBrain = hooks[event].some((group) =>
121→      group.hooks?.some(
122→        (h) => h.command?.startsWith("brain ") || h.prompt?.includes("Brain MCP"),
123→      ),
124→    );
125→
126→    if (!hasBrain) {
127→      hooks[event].push({ hooks: hookDefs as HookEntry[] });
128→      added++;
129→    }
130→  }
131→
132→  settings.hooks = hooks;
133→  await Bun.write(settingsPath, JSON.stringify(settings, null, 2) + "\n");
134→  console.log(`✓ Hooks: .claude/settings.json updated (${added} hooks added)`);
135→}
