172→
173→export function installGitHooks(gitRoot?: string): void {
174→  const root = gitRoot ?? findGitRoot(process.cwd());
175→  if (!root) {
176→    console.log("  No .git directory found — skipping git hook installation.");
177→    return;
178→  }
179→
180→  const hooksDir = join(root, ".git", "hooks");
181→  if (!existsSync(hooksDir)) mkdirSync(hooksDir, { recursive: true });
182→
183→  const preCommitPath = join(hooksDir, "pre-commit");
184→  const postCommitPath = join(hooksDir, "post-commit");
185→  const preCommitScript = `#!/bin/sh
186→# Brain pre-commit hook: check for task completion and unlogged decisions
187→brain check-commit
188→`;
189→
190→  if (!existsSync(preCommitPath)) {
191→    Bun.writeSync(Bun.openSync(preCommitPath, "w"), preCommitScript);
192→    chmodSync(preCommitPath, 0o755);
193→    console.log("✓ Git: pre-commit hook installed");
194→  } else {
195→    console.log("✓ Git: pre-commit hook already exists");
196→  }
197→
198→  // Remove legacy Brain post-commit hook
199→  if (existsSync(postCommitPath)) {
200→    const postCommitContent = Bun.file(postCommitPath).textSync();
201→    const isBrainManaged =
202→      postCommitContent.includes("Brain post-commit hook") &&
203→      postCommitContent.includes("brain log-commit");
204→    if (isBrainManaged) {
205→      unlinkSync(postCommitPath);
206→      console.log("  Removed legacy Brain post-commit hook");
207→    }
208→  }
209→}
