211→async function setupCommands(gitRoot: string): Promise<void> {
212→  const commandsDir = join(gitRoot, ".claude", "commands");
213→  if (!existsSync(commandsDir)) mkdirSync(commandsDir, { recursive: true });
214→
215→  let count = 0;
216→  for (const [filename, content] of Object.entries(BRAIN_COMMANDS)) {
217→    await Bun.write(join(commandsDir, filename), content + "\n");
218→    count++;
219→  }
220→
221→  console.log(`✓ Commands: ${count} slash commands installed to .claude/commands/`);
222→}
