 28→ * Called by SessionStart hook. Loads workspace overview for agent orientation.
 29→ */
 30→export async function runLoadContext(): Promise<void> {
 31→  const config = await requireConfig();
 32→  const client = new BrainHttpClient(config);
 33→
 34→  try {
 35→    const overview = (await client.getWorkspaceContext()) as WorkspaceOverviewResponse;
 36→    console.log(formatWorkspaceOverview(overview));
 37→  } catch (error) {
 38→    console.error(`Failed to load workspace: ${error instanceof Error ? error.message : error}`);
 39→  }
 40→}
