 42→function formatWorkspaceOverview(overview: WorkspaceOverviewResponse): string {
 43→  const lines: string[] = [];
 44→
 45→  lines.push(`# Brain Workspace: ${overview.workspace.name}\n`);
 46→
 47→  if (overview.projects.length === 0) {
 48→    lines.push("No projects found. Create one in the Brain web UI.");
 49→    return lines.join("\n");
 50→  }
 51→
 52→  lines.push("## Projects");
 53→  for (const p of overview.projects) {
 54→    const c = p.counts;
 55→    const counts = `${c.tasks}T ${c.decisions}D ${c.features}F ${c.questions}Q`;
 56→    lines.push(`  - ${p.name} (id: ${p.id}) [${counts}]`);
 57→  }
 58→  lines.push("");
 59→
 60→  const { contested_decisions, open_observations, pending_suggestions } = overview.hot_items;
 61→
 62→  if (contested_decisions.length > 0) {
 63→    lines.push("## Contested Decisions");
 64→    for (const d of contested_decisions) {
 65→      lines.push(`  - ${d.summary} (id: ${d.id})`);
 66→    }
 67→    lines.push("");
 68→  }
 69→
 70→  if (open_observations.length > 0) {
 71→    lines.push("## Open Observations");
 72→    for (const o of open_observations) {
 73→      lines.push(`  - [${o.severity}] ${o.text}`);
 74→    }
 75→    lines.push("");
 76→  }
 77→
 78→  if (pending_suggestions.length > 0) {
 79→    lines.push("## Pending Suggestions");
 80→    for (const s of pending_suggestions) {
 81→      lines.push(`  - [${s.category}] ${s.text}`);
 82→    }
 83→    lines.push("");
 84→  }
 85→
 86→  if (overview.active_sessions.length > 0) {
 87→    lines.push("## Active Agent Sessions");
 88→    for (const s of overview.active_sessions) {
 89→      const taskInfo = s.task ? ` on "${s.task.title}"` : "";
 90→      lines.push(`  - ${s.agent}${taskInfo}`);
 91→    }
 92→    lines.push("");
 93→  }
 94→
 95→  lines.push("Use `get_workspace_context`, `get_project_context`, or `get_task_context` MCP tools for more detail.");
 96→
 97→  return lines.join("\n");
 98→}
