100→/**
101→ * brain system check-updates
102→ * Called by UserPromptSubmit hook. Workspace-level change alerts.
103→ */
104→export async function runCheckUpdates(): Promise<void> {
105→  const config = await requireConfig();
106→  const client = new BrainHttpClient(config);
107→
108→  try {
109→    const since = new Date(Date.now() - 5 * 60_000).toISOString();
110→    const result = (await client.getChanges({ since })) as {
111→      changes: Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }>;
112→    };
113→
114→    if (!result.changes || result.changes.length === 0) return;
115→
116→    const critical = result.changes.filter(
117→      (c) => c.change_type === "contested" || c.change_type === "superseded",
118→    );
119→    if (critical.length > 0) {
120→      console.log("\n--- Context Update ---");
121→      for (const c of critical) {
122→        console.log(`[${c.entity_type}] ${c.entity_name} — ${c.change_type} at ${c.changed_at}`);
123→      }
124→      console.log("--- End Update ---\n");
125→    }
126→
127→    const crossAgent = result.changes.filter(
128→      (c) =>
129→        c.change_type === "provisional" ||
130→        (c.entity_type === "observation" && (c.change_type === "warning" || c.change_type === "conflict")),
131→    );
132→    if (crossAgent.length > 0) {
133→      console.log("\n--- Cross-Agent Activity ---");
134→      for (const c of crossAgent) {
135→        console.log(`[${c.entity_type}] ${c.entity_name} — ${c.change_type}`);
136→      }
137→      console.log("--- End ---\n");
138→    }
139→
140→    const newSuggestions = result.changes.filter(
141→      (c) => c.entity_type === "suggestion" && c.change_type === "pending",
142→    );
143→    if (newSuggestions.length > 0) {
144→      console.log("\n--- New Suggestions ---");
145→      for (const s of newSuggestions) {
146→        console.log(`[suggestion] ${s.entity_name}`);
147→      }
148→      console.log("--- End ---\n");
149→    }
150→  } catch {
151→    // Silent on error — don't block the user
152→  }
153→}
