155→/**
156→ * brain system end-session
157→ * Called by SessionEnd hook. Reads the Stop hook JSON from stdin which includes
158→ * project_id (set by the agent) and session summary.
159→ */
160→export async function runEndSession(): Promise<void> {
161→  const config = await requireConfig();
162→  const client = new BrainHttpClient(config);
163→
164→  try {
165→    // Read stdin (Claude Code pipes Stop hook JSON)
166→    let stdinText = "";
167→    try {
168→      const chunks: Buffer[] = [];
169→      for await (const chunk of Bun.stdin.stream()) {
170→        chunks.push(Buffer.from(chunk));
171→      }
172→      stdinText = Buffer.concat(chunks).toString("utf-8").trim();
173→    } catch {
174→      // stdin not available or empty
175→    }
176→
177→    if (!stdinText) return;
178→
179→    const parsed = JSON.parse(stdinText) as Record<string, unknown>;
180→
181→    if (parsed.decision === "block") {
182→      const reason = typeof parsed.reason === "string" ? parsed.reason : "Stop hook returned block decision";
183→      throw new Error(`Session end blocked: ${reason}`);
184→    }
185→    if (parsed.decision !== "approve") {
186→      throw new Error("Stop hook payload must include decision=\"approve\" or decision=\"block\"");
187→    }
188→    if (typeof parsed.summary !== "string" || parsed.summary.trim().length === 0) {
189→      throw new Error("Stop hook payload must include a non-empty string summary");
190→    }
191→
192→    // project_id comes from the agent via the Stop hook payload (optional)
193→    const projectId = typeof parsed.project_id === "string" ? parsed.project_id : undefined;
194→    const summary = parsed.summary.trim();
195→
196→    const parseStringArray = (key: string): string[] | undefined => {
197→      const val = parsed[key];
198→      if (val === undefined) return undefined;
199→      if (!Array.isArray(val) || !val.every((v) => typeof v === "string")) {
200→        throw new Error(`${key} must be an array of strings`);
201→      }
202→      return val;
203→    };
204→
205→    const decisionsMade = parseStringArray("decisions_made");
206→    const questionsAsked = parseStringArray("questions_asked");
207→    const observationsLogged = parseStringArray("observations_logged");
208→    const subtasksCreated = parseStringArray("subtasks_created");
209→    const suggestionsCreated = parseStringArray("suggestions_created");
210→
211→    let tasksProgressed: Array<{ task_id: string; from_status: string; to_status: string }> | undefined;
212→    if (parsed.tasks_progressed !== undefined) {
213→      if (!Array.isArray(parsed.tasks_progressed)) throw new Error("tasks_progressed must be an array");
214→      tasksProgressed = parsed.tasks_progressed.map((entry) => {
215→        const row = entry as Record<string, unknown>;
216→        if (typeof row.task_id !== "string" || typeof row.from_status !== "string" || typeof row.to_status !== "string") {
217→          throw new Error("tasks_progressed entries must include string task_id, from_status, and to_status");
218→        }
219→        return { task_id: row.task_id, from_status: row.from_status, to_status: row.to_status };
220→      });
221→    }
222→
223→    let filesChanged: Array<{ path: string; change_type: string }> | undefined;
224→    if (parsed.files_changed !== undefined) {
225→      if (!Array.isArray(parsed.files_changed)) throw new Error("files_changed must be an array");
226→      filesChanged = parsed.files_changed.map((entry) => {
227→        const row = entry as Record<string, unknown>;
228→        if (typeof row.path !== "string" || typeof row.change_type !== "string") {
229→          throw new Error("files_changed entries must include string path and change_type");
230→        }
231→        return { path: row.path, change_type: row.change_type };
232→      });
233→    }
234→
235→    // Create session and immediately end it with summary
236→    const session = await client.sessionStart({
237→      agent: "claude-code",
238→      ...(projectId ? { project_id: projectId } : {}),
239→    });
240→
241→    await client.sessionEnd({
242→      session_id: session.session_id,
243→      summary,
244→      decisions_made: decisionsMade,
245→      questions_asked: questionsAsked,
246→      tasks_progressed: tasksProgressed,
247→      files_changed: filesChanged,
248→      observations_logged: observationsLogged,
249→      subtasks_created: subtasksCreated,
250→      suggestions_created: suggestionsCreated,
251→    });
252→  } catch (error) {
253→    console.error(`Brain: Failed to end session: ${error instanceof Error ? error.message : error}`);
254→  }
255→}
