 1→import type { ReagraphNode, ReagraphEdge, GraphResponse, EntityKind } from "../../shared/contracts";
 2→import type { GraphViewRawResult } from "./queries";
 3→
 4→// Resolved hex values for OKLCH entity colors — Three.js/WebGL cannot parse CSS variables.
 5→export function entityColor(kind: EntityKind): string {
 6→  switch (kind) {
 7→    case "project": return "#3b82f6";   // oklch(0.65 0.15 250)
 8→    case "feature": return "#14b8a6";   // oklch(0.65 0.15 170)
 9→    case "task": return "#22c55e";      // oklch(0.70 0.15 145)
10→    case "decision": return "#eab308";  // oklch(0.70 0.15 55)
11→    case "question": return "#a855f7";  // oklch(0.65 0.15 300)
12→    case "observation": return "#ef4444";
13→    case "suggestion": return "#06b6d4"; // cyan-500
14→    case "person": return "#f97316";    // oklch(0.65 0.15 25)
15→    case "workspace": return "#3b82f6";
16→    case "message": return "#22c55e";
17→  }
18→}
19→
20→function titleCase(s: string): string {
21→  return s.split(" ").map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
22→}
23→
24→export function transformToReagraph(raw: GraphViewRawResult): GraphResponse {
25→  const connectionCounts = new Map<string, number>();
26→  for (const edge of raw.edges) {
27→    connectionCounts.set(edge.fromId, (connectionCounts.get(edge.fromId) ?? 0) + 1);
28→    connectionCounts.set(edge.toId, (connectionCounts.get(edge.toId) ?? 0) + 1);
29→  }
30→
31→  const nodes: ReagraphNode[] = raw.entities.map((entity) => {
32→    const kind = entity.kind as EntityKind;
33→    const kindBoost = kind === "project" ? 20
34→      : kind === "feature" ? 10
35→      : kind === "person" ? 8
36→      : 0;
37→    return {
38→      id: entity.id,
39→      label: entity.name.length > 32 ? entity.name.slice(0, 32) + "\u2026" : entity.name,
40→      fill: entityColor(kind),
41→      data: {
42→        kind,
43→        connectionCount: (connectionCounts.get(entity.id) ?? 0) + kindBoost,
44→        status: undefined,
45→      },
46→    };
47→  });
48→
49→  const edges: ReagraphEdge[] = raw.edges.map((edge) => ({
50→    id: edge.id,
51→    source: edge.fromId,
52→    target: edge.toId,
53→    label: titleCase(edge.kind.replace(/_/g, " ")),
54→    data: {
55→      type: edge.kind,
56→      confidence: edge.confidence,
57→    },
58→  }));
59→
60→  return { nodes, edges };
61→}
