 71→function normalizeTokens(value: string): Set<string> {
 72→  return new Set(
 73→    value
 74→      .toLowerCase()
 75→      .replace(/[^a-z0-9\s]/g, " ")
 76→      .split(/\s+/)
 77→      .map((t) => t.trim())
 78→      .filter((t) => t.length > 2),
 79→  );
