109→  async function requireScopedRecord(record: RecordId<string, string>, workspaceRecord: RecordId<"workspace", string>, label: string): Promise<Response | undefined> {
110→    if (record.table.name === "agent_session") {
111→      const session = await surreal.select<{ workspace: RecordId<"workspace", string> }>(record as RecordId<"agent_session", string>);
112→      if (!session) {
113→        return jsonError(`${label} not found`, 404);
114→      }
115→      if ((session.workspace.id as string) !== (workspaceRecord.id as string)) {
116→        return jsonError(`${label} is outside workspace scope`, 404);
117→      }
118→      return undefined;
119→    }
120→
121→    const scoped = await isEntityInWorkspace(surreal, workspaceRecord, record as RecordId<GraphEntityTable, string>);
122→    if (!scoped) {
123→      return jsonError(`${label} is outside workspace scope`, 404);
124→    }
125→    return undefined;
126→  }
