133→  async function handleAuthInit(workspaceId: string): Promise<Response> {
134→    const result = await resolveWorkspaceById(workspaceId);
135→    if (result instanceof Response) return result;
136→
137→    const apiKey = generateApiKey();
138→    const hash = await hashApiKey(apiKey);
139→
140→    await surreal.update(result.workspaceRecord).merge({ api_key_hash: hash, updated_at: new Date() });
141→
142→    logInfo("mcp.auth.init", "API key generated for workspace", { workspaceId });
143→
144→    return jsonResponse({ api_key: apiKey, workspace: { id: workspaceId, name: result.workspace.name } }, 200);
