147→  /** GET /api/mcp/:workspaceId/projects — List workspace projects */
148→  async function handleListProjects(workspaceId: string): Promise<Response> {
149→    const result = await resolveWorkspaceById(workspaceId);
150→    if (result instanceof Response) return result;
151→
152→    const [projectRows] = await surreal
153→      .query<[ProjectRow[]]>(
154→        "SELECT id, name FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
155→        { workspace: result.workspaceRecord },
156→      )
157→      .collect<[ProjectRow[]]>();
158→
159→    return jsonResponse({
160→      workspace: { id: workspaceId, name: result.workspace.name },
161→      projects: projectRows.map((p) => ({ id: p.id.id as string, name: p.name })),
162→    }, 200);
