 71→    71→    71→function normalizeTokens(value: string): Set<string> {
 72→    72→    72→  return new Set(
 73→    73→    73→    value
 74→    74→    74→      .toLowerCase()
 75→    75→    75→      .replace(/[^a-z0-9\s]/g, " ")
 76→    76→    76→      .split(/\s+/)
 77→    77→    77→      .map((t) => t.trim())
 78→    78→    78→      .filter((t) => t.length > 2),
 79→    79→    79→  );
 80→    80→    80→}
