 82→    82→    82→function hasTokenOverlap(a: Set<string>, b: Set<string>): boolean {
 83→    83→    83→  for (const v of a) {
 84→    84→    84→    if (b.has(v)) return true;
 85→    85→    85→  }
 86→    86→    86→  return false;
 87→    87→    87→}
