502→  /** POST /api/mcp/:workspaceId/constraints/check — Check proposed action */
503→  async function handleCheckConstraints(workspaceId: string, request: Request): Promise<Response> {
504→    const auth = await requireAuth(request, workspaceId);
505→    if (auth instanceof Response) return auth;
506→
507→    const body = await parseJsonBody<{ proposed_action: string; project?: string }>(request);
508→    if (body instanceof Response) return body;
509→    if (!body.proposed_action) return jsonError("proposed_action is required", 400);
510→
511→    const queryEmbedding = await createEmbeddingVector(
512→      deps.embeddingModel,
513→      body.proposed_action,
514→      config.embeddingDimension,
515→    );
516→
517→    if (!queryEmbedding) {
518→      return jsonResponse({ hard_conflicts: [], soft_tensions: [], supporting: [], proceed: true }, 200);
519→    }
520→
521→    const projectRecord = body.project
522→      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.project })
523→      : undefined;
524→
525→    const candidates = await listDecisionConstraintCandidates({
526→      surreal,
527→      workspaceRecord: auth.workspaceRecord,
528→      queryEmbedding,
529→      ...(projectRecord ? { projectRecord } : {}),
530→      limit: 14,
531→    });
532→
533→    const actionTokens = normalizeTokens(body.proposed_action);
534→    const hardConflicts: Array<{ id: string; name: string; score: number; reason: string }> = [];
535→    const softTensions: Array<{ id: string; name: string; score: number; reason: string }> = [];
536→    const supporting: Array<{ id: string; name: string; score: number; reason: string }> = [];
537→
538→    for (const candidate of candidates) {
539→      const candidateTokens = normalizeTokens(candidate.name);
540→      const overlap = hasTokenOverlap(actionTokens, candidateTokens);
541→      const status = candidate.status?.toLowerCase();
542→
543→      if (candidate.kind === "decision" && overlap && (status === "contested" || status === "superseded")) {
544→        hardConflicts.push({
545→          id: `${candidate.kind}:${candidate.id}`,
546→          name: candidate.name,
547→          score: Number(candidate.score.toFixed(4)),
548→          reason: `Decision is marked ${status}.`,
549→        });
550→        continue;
551→      }
552→
553→      if (candidate.kind === "decision" && candidate.score >= 0.86 && overlap) {
554→        supporting.push({
555→          id: `${candidate.kind}:${candidate.id}`,
556→          name: candidate.name,
557→          score: Number(candidate.score.toFixed(4)),
558→          reason: "High-similarity decision aligns with proposed action.",
559→        });
560→        continue;
561→      }
562→
563→      if (candidate.score >= 0.72) {
564→        softTensions.push({
565→          id: `${candidate.kind}:${candidate.id}`,
566→          name: candidate.name,
567→          score: Number(candidate.score.toFixed(4)),
568→          reason: overlap
569→            ? "Related decision/question may require consistency checks."
570→            : "Semantically related context may be affected.",
571→        });
572→      }
573→    }
574→
575→    return jsonResponse({ hard_conflicts: hardConflicts, soft_tensions: softTensions, supporting, proceed: hardConflicts.length === 0 }, 200);
576→  }
