  1→import { existsSync, mkdirSync, statSync } from "node:fs";
  2→import { join, dirname, resolve } from "node:path";
  3→import { homedir } from "node:os";
  4→
  5→const BRAIN_DIR = join(homedir(), ".brain");
  6→const CONFIG_PATH = join(BRAIN_DIR, "config.json");
  7→
  8→/** Resolved config for a single repo — shape consumed by BrainHttpClient and all commands. */
  9→export type BrainConfig = {
 10→  server_url: string;
 11→  workspace: string;
 12→  api_key: string;
 13→};
 14→
 15→/** Per-repo auth entry in ~/.brain/config.json */
 16→export type RepoConfig = {
 17→  workspace: string;
 18→  api_key: string;
 19→};
 20→
 21→/** Root shape of ~/.brain/config.json */
 22→export type BrainGlobalConfig = {
 23→  server_url: string;
 24→  repos: Record<string, RepoConfig>;
 25→};
 26→
 27→// ---------------------------------------------------------------------------
 28→// Git root
 29→// ---------------------------------------------------------------------------
 30→
 31→/**
 32→ * Find the main repository root from any path, including worktrees.
 33→ *
 34→ * In a regular repo, `.git` is a directory → that dir is the root.
 35→ * In a worktree, `.git` is a file containing `gitdir: /path/to/main/.git/worktrees/<name>`.
 36→ * We follow the pointer back to the main repo so all worktrees share one config key.
 37→ */
 38→export function findGitRoot(from: string): string | undefined {
 39→  let dir = from;
 40→  while (dir !== "/") {
 41→    const gitPath = join(dir, ".git");
 42→    if (existsSync(gitPath)) {
 43→      if (statSync(gitPath).isFile()) {
 44→        return resolveWorktreeMainRoot(gitPath) ?? dir;
 45→      }
 46→      return dir;
 47→    }
 48→    dir = dirname(dir);
 49→  }
 50→  return undefined;
 51→}
 52→
 53→/** Read a worktree .git file and resolve to the main repo root. */
 54→function resolveWorktreeMainRoot(gitFile: string): string | undefined {
 55→  try {
 56→    const content = Bun.file(gitFile).textSync().trim();
 57→    const match = content.match(/^gitdir:\s*(.+)$/);
 58→    if (!match) return undefined;
 59→
 60→    const gitdir = resolve(dirname(gitFile), match[1]);
 61→    const dotGit = gitdir.replace(/\/worktrees\/[^/]+$/, "");
 62→    return dirname(dotGit);
 63→  } catch {
 64→    return undefined;
 65→  }
 66→}
 67→
 68→// ---------------------------------------------------------------------------
 69→// Global config (~/.brain/config.json)
 70→// ---------------------------------------------------------------------------
 71→
 72→function ensureBrainDir(): void {
 73→  if (!existsSync(BRAIN_DIR)) mkdirSync(BRAIN_DIR, { recursive: true });
 74→}
 75→
 76→export async function loadGlobalConfig(): Promise<BrainGlobalConfig | undefined> {
 77→  const file = Bun.file(CONFIG_PATH);
 78→  if (!(await file.exists())) return undefined;
 79→  try {
 80→    return await file.json() as BrainGlobalConfig;
 81→  } catch {
 82→    return undefined;
 83→  }
 84→}
 85→
 86→export async function saveGlobalConfig(config: BrainGlobalConfig): Promise<void> {
 87→  ensureBrainDir();
 88→  await Bun.write(CONFIG_PATH, JSON.stringify(config, null, 2) + "\n");
 89→}
 90→
 91→/** Upsert a repo entry in the global config. Creates the file if needed. */
 92→export async function saveRepoConfig(serverUrl: string, gitRoot: string, repo: RepoConfig): Promise<void> {
 93→  const global = (await loadGlobalConfig()) ?? { server_url: serverUrl, repos: {} };
 94→  global.server_url = serverUrl;
 95→  global.repos[gitRoot] = repo;
 96→  await saveGlobalConfig(global);
 97→}
 98→
 99→// ---------------------------------------------------------------------------
100→// Resolved config (what consumers use)
101→// ---------------------------------------------------------------------------
102→
103→/** Resolve BrainConfig for the current repo from ~/.brain/config.json.
104→ *  The server URL can be overridden via the BRAIN_SERVER_URL env var. */
105→export async function loadConfig(): Promise<BrainConfig | undefined> {
106→  const gitRoot = findGitRoot(process.cwd());
107→  const global = await loadGlobalConfig();
108→  if (global && gitRoot && global.repos[gitRoot]) {
109→    const repo = global.repos[gitRoot];
110→    const serverUrl = process.env.BRAIN_SERVER_URL ?? global.server_url;
111→    return { server_url: serverUrl, workspace: repo.workspace, api_key: repo.api_key };
112→  }
113→  return undefined;
114→}
115→
116→export async function requireConfig(): Promise<BrainConfig> {
117→  const config = await loadConfig();
118→  if (!config) {
119→    console.error("Brain not configured. Run: brain init");
120→    process.exit(1);
121→  }
122→  return config;
123→}
