318→
319→  static async listProjects(serverUrl: string, workspaceId: string): Promise<{ workspace: { id: string; name: string }; projects: Array<{ id: string; name: string }> }> {
320→    const url = `${serverUrl.replace(/\/$/, "")}/api/mcp/${workspaceId}/projects`;
321→    const res = await fetch(url, { headers: { "Content-Type": "application/json" } });
322→    if (!res.ok) throw new Error(`Failed to list projects: ${res.status} ${await res.text()}`);
323→    return res.json() as Promise<{ workspace: { id: string; name: string }; projects: Array<{ id: string; name: string }> }>;
324→  }
325→}
