  1→import { existsSync, mkdirSync, chmodSync, unlinkSync } from "node:fs";
  2→import { join } from "node:path";
  3→import { findGitRoot, saveRepoConfig, loadGlobalConfig } from "../config";
  4→import { BrainHttpClient } from "../http-client";
  5→import { BRAIN_HOOKS, BRAIN_CLAUDE_MD, BRAIN_COMMANDS } from "./init-content";
  6→
  7→const DEFAULT_SERVER_URL = "http://localhost:3000";
  8→
  9→export async function runInit(): Promise<void> {
 10→  const serverUrl = process.env.BRAIN_SERVER_URL ?? DEFAULT_SERVER_URL;
 11→  const workspaceId = process.env.BRAIN_WORKSPACE_ID;
 12→
 13→  const gitRoot = findGitRoot(process.cwd());
 14→  if (!gitRoot) {
 15→    console.error("Not inside a git repository. Run brain init from a project directory.");
 16→    process.exit(1);
 17→  }
 18→
 19→  if (!workspaceId) {
 20→    console.error("Set BRAIN_WORKSPACE_ID env var to your workspace ID.");
 21→    console.error("Find it in the Brain web UI or the database.");
 22→    process.exit(1);
 23→  }
 24→
 25→  console.log("Brain Init\n──────────\n");
 26→
 27→  // Step 1: Auth
 28→  await setupAuth(serverUrl, workspaceId, gitRoot);
 29→
 30→  // Step 2: .mcp.json
 31→  await setupMcpJson(gitRoot);
 32→
 33→  // Step 3: .claude/settings.json hooks
 34→  await setupClaudeHooks(gitRoot);
 35→
 36→  // Step 4: CLAUDE.md
 37→  await setupClaudeMd(gitRoot);
 38→
 39→  // Step 5: Commands
 40→  await setupCommands(gitRoot);
 41→
 42→  // Step 6: Git hooks
 43→  installGitHooks(gitRoot);
 44→
 45→  console.log(`\nDone. Restart Claude Code to activate.`);
 46→}
 47→
 48→// ---------------------------------------------------------------------------
 49→// Step 1: Auth
 50→// ---------------------------------------------------------------------------
 51→
 52→async function setupAuth(serverUrl: string, workspaceId: string, gitRoot: string): Promise<void> {
 53→  const global = await loadGlobalConfig();
 54→  const existing = global?.repos[gitRoot];
 55→  if (existing && existing.workspace === workspaceId) {
 56→    console.log(`✓ Auth: already configured for ${gitRoot}`);
 57→    return;
 58→  }
 59→
 60→  const initResult = await BrainHttpClient.initApiKey(serverUrl, workspaceId);
 61→  await saveRepoConfig(serverUrl, gitRoot, {
 62→    workspace: workspaceId,
 63→    api_key: initResult.api_key,
 64→  });
 65→  console.log(`✓ Auth: API key saved for ${gitRoot} → workspace "${initResult.workspace.name}"`);
 66→}
 67→
 68→// ---------------------------------------------------------------------------
 69→// Step 2: .mcp.json
 70→// ---------------------------------------------------------------------------
 71→
 72→async function setupMcpJson(gitRoot: string): Promise<void> {
 73→  const mcpPath = join(gitRoot, ".mcp.json");
 74→  const file = Bun.file(mcpPath);
 75→  let mcp: { mcpServers: Record<string, unknown> } = { mcpServers: {} };
 76→
 77→  if (await file.exists()) {
 78→    try {
 79→      mcp = await file.json();
 80→      mcp.mcpServers ??= {};
 81→    } catch {
 82→      // Corrupted file — overwrite
 83→    }
 84→  }
 85→
 86→  mcp.mcpServers.brain = { command: "brain", args: ["mcp"] };
 87→  await Bun.write(mcpPath, JSON.stringify(mcp, null, 2) + "\n");
 88→  console.log("✓ MCP: .mcp.json updated");
 89→}
 90→
 91→// ---------------------------------------------------------------------------
 92→// Step 3: .claude/settings.json hooks
 93→// ---------------------------------------------------------------------------
 94→
 95→type HookEntry = { type: string; command?: string; prompt?: string };
 96→type SettingsHookGroup = { matcher?: string; hooks: HookEntry[] };
 97→
 98→async function setupClaudeHooks(gitRoot: string): Promise<void> {
 99→  const claudeDir = join(gitRoot, ".claude");
100→  if (!existsSync(claudeDir)) mkdirSync(claudeDir, { recursive: true });
101→
102→  const settingsPath = join(claudeDir, "settings.json");
103→  const file = Bun.file(settingsPath);
104→  let settings: Record<string, unknown> = {};
105→
106→  if (await file.exists()) {
107→    try {
108→      settings = await file.json();
109→    } catch {
110→      // Corrupted — start fresh
111→    }
112→  }
113→
114→  const hooks = (settings.hooks ?? {}) as Record<string, SettingsHookGroup[]>;
115→  let added = 0;
116→
117→  for (const [event, hookDefs] of Object.entries(BRAIN_HOOKS)) {
118→    hooks[event] ??= [];
119→
120→    const hasBrain = hooks[event].some((group) =>
121→      group.hooks?.some(
122→        (h) => h.command?.startsWith("brain ") || h.prompt?.includes("Brain MCP"),
123→      ),
124→    );
125→
126→    if (!hasBrain) {
127→      hooks[event].push({ hooks: hookDefs as HookEntry[] });
128→      added++;
129→    }
130→  }
131→
132→  settings.hooks = hooks;
133→  await Bun.write(settingsPath, JSON.stringify(settings, null, 2) + "\n");
134→  console.log(`✓ Hooks: .claude/settings.json updated (${added} hooks added)`);
135→}
136→
137→// ---------------------------------------------------------------------------
138→// Step 4: CLAUDE.md
139→// ---------------------------------------------------------------------------
140→
141→const MARKER_START = "<!-- brain-plugin-start -->";
142→const MARKER_END = "<!-- brain-plugin-end -->";
143→
144→async function setupClaudeMd(gitRoot: string): Promise<void> {
145→  const claudeMdPath = join(gitRoot, "CLAUDE.md");
146→  const file = Bun.file(claudeMdPath);
147→  let content = "";
148→
149→  if (await file.exists()) {
150→    content = await file.text();
151→  }
152→
153→  const brainBlock = `${MARKER_START}\n${BRAIN_CLAUDE_MD}\n${MARKER_END}`;
154→
155→  const startIdx = content.indexOf(MARKER_START);
156→  const endIdx = content.indexOf(MARKER_END);
157→
158→  if (startIdx !== -1 && endIdx !== -1) {
159→    content = content.slice(0, startIdx) + brainBlock + content.slice(endIdx + MARKER_END.length);
160→  } else {
161→    const separator = content.length > 0 && !content.endsWith("\n\n") ? "\n\n" : "";
162→    content = content + separator + brainBlock + "\n";
163→  }
164→
165→  await Bun.write(claudeMdPath, content);
166→  console.log("✓ CLAUDE.md: Brain plugin instructions added");
167→}
168→
169→// ---------------------------------------------------------------------------
170→// Step 6: Git hooks
171→// ---------------------------------------------------------------------------
172→
173→export function installGitHooks(gitRoot?: string): void {
174→  const root = gitRoot ?? findGitRoot(process.cwd());
175→  if (!root) {
176→    console.log("  No .git directory found — skipping git hook installation.");
177→    return;
178→  }
179→
180→  const hooksDir = join(root, ".git", "hooks");
181→  if (!existsSync(hooksDir)) mkdirSync(hooksDir, { recursive: true });
182→
183→  const preCommitPath = join(hooksDir, "pre-commit");
184→  const postCommitPath = join(hooksDir, "post-commit");
185→  const preCommitScript = `#!/bin/sh
186→# Brain pre-commit hook: check for task completion and unlogged decisions
187→brain check-commit
188→`;
189→
190→  if (!existsSync(preCommitPath)) {
191→    Bun.writeSync(Bun.openSync(preCommitPath, "w"), preCommitScript);
192→    chmodSync(preCommitPath, 0o755);
193→    console.log("✓ Git: pre-commit hook installed");
194→  } else {
195→    console.log("✓ Git: pre-commit hook already exists");
196→  }
197→
198→  // Remove legacy Brain post-commit hook
199→  if (existsSync(postCommitPath)) {
200→    const postCommitContent = Bun.file(postCommitPath).textSync();
201→    const isBrainManaged =
202→      postCommitContent.includes("Brain post-commit hook") &&
203→      postCommitContent.includes("brain log-commit");
204→    if (isBrainManaged) {
205→      unlinkSync(postCommitPath);
206→      console.log("  Removed legacy Brain post-commit hook");
207→    }
208→  }
209→}
210→
211→async function setupCommands(gitRoot: string): Promise<void> {
212→  const commandsDir = join(gitRoot, ".claude", "commands");
213→  if (!existsSync(commandsDir)) mkdirSync(commandsDir, { recursive: true });
214→
215→  let count = 0;
216→  for (const [filename, content] of Object.entries(BRAIN_COMMANDS)) {
217→    await Bun.write(join(commandsDir, filename), content + "\n");
218→    count++;
219→  }
220→
221→  console.log(`✓ Commands: ${count} slash commands installed to .claude/commands/`);
222→}
223→
