    lines.push("");
    lines.push("When using Brain MCP tools from this directory:");
    lines.push(
      `- Scope \`create_provisional_decision\` / \`ask_question\` with \`context: { feature: "${id}" }\``,
    );
  }

  return lines.join("\n");
}

function taskTemplate(name: string, id: string, projectId?: string): string {
